                    abbr[j] = abbrev(words[j], prefixLen[j] + 1);
                    prefixLen[j]++;
                }
            }
            abbr[i] = abbrev(words[i], prefixLen[i] + 1);
            prefixLen[i]++;
        }
    }

    return abbr;
}
